// Uses Isar (or Hive) for local storage. UI observes via Stream.

abstract class OrderRepository {
  Stream<List<Order>> watchAll();      // UI subscribes here
  Future<void> refresh();              // pull-to-refresh calls this
  Future<void> place(Cart cart);       // optimistic write
}

class OrderRepositoryImpl implements OrderRepository {
  OrderRepositoryImpl(this._remote, this._local, this._outbox, this._connectivity, this._sync);
  final OrderRemoteDataSource _remote;
  final OrderLocalDataSource _local;
  final OutboxDao _outbox;
  final ConnectivityService _connectivity;
  final SyncWorker _sync;

  @override
  Stream<List<Order>> watchAll() => _local.watchAll();

  @override
  Future<void> refresh() async {
    if (!await _connectivity.isOnline) return;   // offline? try later.
    try {
      final fresh = await _remote.fetchAll();
      await _local.replaceAll(fresh);              // Stream re-emits.
    } catch (_) { /* silent — UI already has cached data */ }
  }

  @override
  Future<void> place(Cart cart) async {
    // 1. Build a local order marked 'pending'.
    final draft = Order.newDraft(cart, syncStatus: SyncStatus.pending);

    // 2. Optimistic write — UI updates INSTANTLY via the Stream.
    await _local.upsert(draft);

    // 3. Queue the mutation in the outbox.
    await _outbox.enqueue(PlaceOrderMutation(draft));

    // 4. Kick off sync (fire-and-forget). WorkManager / periodic timer will
    //    also run this every N minutes when we're online.
    _sync.tryRunAll();
  }
}

// The SyncWorker
class SyncWorker {
  SyncWorker(this._outbox, this._remote, this._local, this._connectivity);

  final OutboxDao _outbox;
  final OrderRemoteDataSource _remote;
  final OrderLocalDataSource _local;
  final ConnectivityService _connectivity;

  Future<void> tryRunAll() async {
    if (!await _connectivity.isOnline) return;

    final pending = await _outbox.pendingOrdered();
    for (final mutation in pending) {
      try {
        final serverOrder = await _remote.place(mutation.order);
        await _local.upsert(serverOrder.copyWith(syncStatus: SyncStatus.synced));
        await _outbox.markSynced(mutation.id);
      } on ConflictException catch (e) {
        // Server has a newer version; reconcile.
        final resolved = _reconcile(mutation.order, e.serverVersion);
        await _local.upsert(resolved);
        await _outbox.markSynced(mutation.id);
      } catch (_) {
        // Network / server error — backoff. Outbox stays; retry next tick.
      }
    }
  }

  Order _reconcile(Order local, Order server) {
    // Simple last-write-wins for demo. Real apps use CRDTs or merge rules.
    return server.updatedAt.isAfter(local.updatedAt) ? server : local;
  }
}

// The UI just observes and displays:
class OrdersScreen extends StatelessWidget {
  const OrdersScreen({super.key});
  @override
  Widget build(BuildContext c) => StreamBuilder<List<Order>>(
    stream: getIt<OrderRepository>().watchAll(),
    builder: (_, snap) {
      final orders = snap.data ?? [];
      return RefreshIndicator(
        onRefresh: getIt<OrderRepository>().refresh,
        child: ListView(children: orders.map((o) => OrderTile(o)).toList()),
      );
    },
  );
}
